const email = $input.item.json;
const subject = (email.subject || '').toLowerCase();
const body = (email.text || email.snippet || '').toLowerCase();
const fullText = subject + ' ' + body;

let emailType = 'unknown';
let status = 'unknown';

// Detect rejection
if (fullText.includes('unfortunately') || fullText.includes('not moving forward') ||
    fullText.includes('decided to proceed with other') || fullText.includes('not selected') ||
    fullText.includes('not a match') || fullText.includes('position has been filled') ||
    fullText.includes('we regret') || fullText.includes('other candidates')) {
  emailType = 'rejection';
  status = 'rejected';
}
// Detect offer
else if (fullText.includes('offer') && (fullText.includes('pleased') || fullText.includes('excited') ||
    fullText.includes('compensation') || fullText.includes('salary') || fullText.includes('start date'))) {
  emailType = 'offer';
  status = 'offer_received';
}
// Detect final interview
else if ((fullText.includes('final') || fullText.includes('last')) &&
    (fullText.includes('interview') || fullText.includes('round'))) {
  emailType = 'final_interview';
  status = 'final_round_scheduled';
}
// Detect technical interview
else if (fullText.includes('technical') && fullText.includes('interview')) {
  emailType = 'technical_interview';
  status = 'technical_scheduled';
}
// Detect phone screen
else if ((fullText.includes('phone') || fullText.includes('call') || fullText.includes('screening')) &&
    (fullText.includes('schedule') || fullText.includes('interview') || fullText.includes('chat'))) {
  emailType = 'phone_screen';
  status = 'phone_screen_scheduled';
}
// Detect moving forward
else if (fullText.includes('moving forward') || fullText.includes('next steps') ||
    fullText.includes('next round') || fullText.includes('advance')) {
  emailType = 'moving_forward';
  status = 'phone_screen_scheduled';
}

// Extract company name from email sender or subject
const senderEmail = (email.from || '').toLowerCase();
const senderDomain = senderEmail.includes('@') ? senderEmail.split('@')[1].split('.')[0] : '';

return [{
  json: {
    ...email,
    email_type: emailType,
    new_status: status,
    sender_company: senderDomain,
    processed_at: new Date().toISOString()
  }
}];

const emailData = $input.item.json;
const githubToken = process.env.GITHUB_TOKEN || '';

if (!githubToken) {
  return [{
    json: {
      ...emailData,
      update_status: 'skipped',
      skip_reason: 'No GITHUB_TOKEN'
    }
  }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const apiBase = 'https://api.github.com';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: apiBase + path,
    headers: headers,
    body: body
  });
}

// Determine target folder based on new status
function getTargetFolder(status) {
  const folderMap = {
    'applied': 'Job_Applications/Active',
    'phone_screen_scheduled': 'Job_Applications/Waiting',
    'technical_scheduled': 'Job_Applications/Waiting',
    'final_round_scheduled': 'Job_Applications/Waiting',
    'offer_received': 'Job_Applications/Offers',
    'rejected': 'Job_Applications/Rejected'
  };
  return folderMap[status] || 'Job_Applications/Active';
}

// Ensure folder exists by creating .gitkeep if needed
async function ensureFolderExists(folderPath) {
  try {
    const gitkeepPath = 'Obsidian_Vault/' + folderPath + '/.gitkeep';
    await apiRequest('GET', '/repos/' + owner + '/' + repo + '/contents/' + gitkeepPath);
  } catch(e) {
    // Folder doesn't exist, create .gitkeep
    try {
      const refData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/refs/heads/main');
      const currentSha = refData.object.sha;
      const commitData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/commits/' + currentSha);
      const treeSha = commitData.tree.sha;

      const blobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
        content: '',
        encoding: 'utf-8'
      });

      const newTreeData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/trees', {
        base_tree: treeSha,
        tree: [{ path: 'Obsidian_Vault/' + folderPath + '/.gitkeep', mode: '100644', type: 'blob', sha: blobData.sha }]
      });

      const newCommitData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/commits', {
        message: 'Auto-create folder: ' + folderPath,
        tree: newTreeData.sha,
        parents: [currentSha]
      });

      await apiRequest('PATCH', '/repos/' + owner + '/' + repo + '/git/refs/heads/main', {
        sha: newCommitData.sha,
        force: false
      });
    } catch(createErr) {
      console.error('Error creating folder ' + folderPath + ':', createErr.message);
    }
  }
}

const newStatus = emailData.new_status;
const targetFolder = getTargetFolder(newStatus);
await ensureFolderExists(targetFolder);

// Log entry for communication log
const logEntry = '- **' + new Date().toISOString().split('T')[0] + '** | ' +
  emailData.email_type.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) + ' | ' +
  'From: ' + (emailData.from || 'Unknown') + '\n';

return [{
  json: {
    ...emailData,
    target_folder: targetFolder,
    log_entry: logEntry,
    update_status: 'processed'
  }
}];

const emailData = $input.item.json;

// Only generate response for rejections
if (emailData.email_type !== 'rejection') {
  return [{ json: { ...emailData, skip_response: true } }];
}

async function callOllama(prompt) {
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'http://ollama:11434/api/generate',
        headers: { 'Content-Type': 'application/json' },
        body: { model: 'llama3.2', prompt: prompt, stream: false }
      });
      return (resp && resp.response) ? resp.response : '[No response]';
    } catch (e) {
      if (attempt === 3) return '[Ollama Error: ' + e.message + ']';
      await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000));
    }
  }
}

const rejectionStage = emailData.rejection_stage || 'phone_screen';
const companyName = emailData.sender_company || 'the company';

let templateContext = '';
if (rejectionStage === 'phone_screen') {
  templateContext = 'This was rejected after a phone screen (minimal investment from both sides). Keep response brief and professional.';
} else if (rejectionStage === 'technical') {
  templateContext = 'This was rejected after a technical interview. Show appreciation for the technical depth of the process. Request specific technical feedback.';
} else if (rejectionStage === 'final_round') {
  templateContext = 'This was rejected after the final round. The company invested significant time. Response should be warmer and more personal. Express genuine gratitude.';
}

const prompt = 'Write a professional rejection response email to ' + companyName + ' for a ' + emailData.email_type + ' at the ' + rejectionStage + ' stage. ' + templateContext + ' The email should: 1) Thank them professionally 2) Request feedback 3) Keep the door open for future opportunities 4) Be genuine, not bitter. Keep it to 3-4 short paragraphs. Sign as Odeliya Charitonova.';

const responseEmail = await callOllama(prompt);

return [{
  json: {
    ...emailData,
    rejection_response_draft: responseEmail,
    rejection_stage: rejectionStage,
    skip_response: false
  }
}];
